change_filament_gcode:
{if next_extruder == 0}
SELECT_PH1
{elsif next_extruder == 1}
SELECT_PH2
{elsif next_extruder == 2}
SELECT_PH3
{elsif next_extruder == 3}
SELECT_PH4
{elsif next_extruder == 4}
SELECT_PH5
{endif}

G1 Z{layer_z} F24000

machine_start_gcode:
M83

M140 S{first_layer_bed_temperature[initial_tool]} ; Set bed temp
M104 S150 T0 ; Set PH1 temp for probing/calibration
{if is_extruder_used[1]}M104 T1 S{first_layer_temperature[1]}{endif}
{if is_extruder_used[2]}M104 T2 S{first_layer_temperature[2]}{endif}
{if is_extruder_used[3]}M104 T3 S{first_layer_temperature[3]}{endif}
{if is_extruder_used[4]}M104 T4 S{first_layer_temperature[4]}{endif}

G28 ; Home
DOCK
M190 S{first_layer_bed_temperature[initial_tool]} ; Wait for bed temp
M109 S150 T0 ; Wait for PH1 temp
G28 Z ; Home Z
BED_MESH_SCAN
_CAL_SELECT_T0 ; Select and wipe PH1
TAP
DOCK
M104 S0 T0 ; Turn off PH1 after tap if not needed immediately

{if is_extruder_used[0]}M104 T0 S{first_layer_temperature[0]}{endif}
{if is_extruder_used[1]}M104 T1 S{first_layer_temperature[1]}{endif}
{if is_extruder_used[2]}M104 T2 S{first_layer_temperature[2]}{endif}
{if is_extruder_used[3]}M104 T3 S{first_layer_temperature[3]}{endif}
{if is_extruder_used[4]}M104 T4 S{first_layer_temperature[4]}{endif}

{if is_extruder_used[0]}M109 T0 S{first_layer_temperature[0]}{endif}
{if is_extruder_used[1]}M109 T1 S{first_layer_temperature[1]}{endif}
{if is_extruder_used[2]}M109 T2 S{first_layer_temperature[2]}{endif}
{if is_extruder_used[3]}M109 T3 S{first_layer_temperature[3]}{endif}
{if is_extruder_used[4]}M109 T4 S{first_layer_temperature[4]}{endif}

UPDATE_DELAYED_GCODE ID=FILTER_FAN_OFF DURATION=0
;SET_FAN_SPEED FAN=filter_fan SPEED=1

; Prime/wipe used non-initial tools left -> right

{if is_extruder_used[0] and initial_tool != 0}
G1 F{travel_speed * 60}
M109 T0 S{first_layer_temperature[0]}
SELECT_PH1
G92 E0
G0 X0 Y0 Z10 F{travel_speed * 60}
G0 E{if filament_multitool_ramming[0]}10{else}30{endif} X40 Z0.2 F{if filament_multitool_ramming[0]}500{else}170{endif}
G0 X40 E9 F800
G0 X43 Z0.05 F8000
G0 X46 Z0.2 F8000
G1 E{-1.5 * retract_length[0]} F2400
{e_retracted[0] = 1.5 * retract_length[0]}
G92 E0
M104 S{(idle_temperature[0] == 0 ? (first_layer_temperature[0] + standby_temperature_delta) : idle_temperature[0])} T0
DOCK
{endif}

{if is_extruder_used[1] and initial_tool != 1}
G1 F{travel_speed * 60}
M109 T1 S{first_layer_temperature[1]}
SELECT_PH2
G92 E0
G0 X40 Y0 Z10 F{travel_speed * 60}
G0 E{if filament_multitool_ramming[1]}10{else}30{endif} X80 Z0.2 F{if filament_multitool_ramming[1]}500{else}170{endif}
G0 X80 E9 F800
G0 X83 Z0.05 F8000
G0 X86 Z0.2 F8000
G1 E{-1.5 * retract_length[1]} F2400
{e_retracted[1] = 1.5 * retract_length[1]}
G92 E0
M104 S{(idle_temperature[1] == 0 ? (first_layer_temperature[1] + standby_temperature_delta) : idle_temperature[1])} T1
DOCK
{endif}

{if is_extruder_used[2] and initial_tool != 2}
G1 F{travel_speed * 60}
M109 T2 S{first_layer_temperature[2]}
SELECT_PH3
G92 E0
G0 X80 Y0 Z10 F{travel_speed * 60}
G0 E{if filament_multitool_ramming[2]}10{else}30{endif} X120 Z0.2 F{if filament_multitool_ramming[2]}500{else}170{endif}
G0 X120 E9 F800
G0 X123 Z0.05 F8000
G0 X126 Z0.2 F8000
G1 E{-1.5 * retract_length[2]} F2400
{e_retracted[2] = 1.5 * retract_length[2]}
G92 E0
M104 S{(idle_temperature[2] == 0 ? (first_layer_temperature[2] + standby_temperature_delta) : idle_temperature[2])} T2
DOCK
{endif}

{if is_extruder_used[3] and initial_tool != 3}
G1 F{travel_speed * 60}
M109 T3 S{first_layer_temperature[3]}
SELECT_PH4
G92 E0
G0 X120 Y0 Z10 F{travel_speed * 60}
G0 E{if filament_multitool_ramming[3]}10{else}30{endif} X160 Z0.2 F{if filament_multitool_ramming[3]}500{else}170{endif}
G0 X160 E9 F800
G0 X163 Z0.05 F8000
G0 X166 Z0.2 F8000
G1 E{-1.5 * retract_length[3]} F2400
{e_retracted[3] = 1.5 * retract_length[3]}
G92 E0
M104 S{(idle_temperature[3] == 0 ? (first_layer_temperature[3] + standby_temperature_delta) : idle_temperature[3])} T3
DOCK
{endif}

{if is_extruder_used[4] and initial_tool != 4}
G1 F{travel_speed * 60}
M109 T4 S{first_layer_temperature[4]}
SELECT_PH5
G92 E0
G0 X160 Y3 Z10 F{travel_speed * 60}
G0 E{if filament_multitool_ramming[4]}10{else}30{endif} X200 Z0.2 F{if filament_multitool_ramming[4]}500{else}170{endif}
G0 X200 E9 F800
G0 X203 Z0.05 F8000
G0 X206 Z0.2 F8000
G1 E{-1.5 * retract_length[4]} F2400
{e_retracted[4] = 1.5 * retract_length[4]}
G92 E0
M104 S{(idle_temperature[4] == 0 ? (first_layer_temperature[4] + standby_temperature_delta) : idle_temperature[4])} T4
DOCK
{endif}

; Prime/wipe initial tool left -> right

G1 F{travel_speed * 60}
M109 T{initial_tool} S{first_layer_temperature[initial_tool]}

{if initial_tool == 0}
SELECT_PH1
{elsif initial_tool == 1}
SELECT_PH2
{elsif initial_tool == 2}
SELECT_PH3
{elsif initial_tool == 3}
SELECT_PH4
{elsif initial_tool == 4}
SELECT_PH5
{endif}

G92 E0
G0 X{(initial_tool == 0 ? 0 : (initial_tool == 1 ? 40 : (initial_tool == 2 ? 80 : (initial_tool == 3 ? 120 : 160))))} Y{(initial_tool < 4 ? 0 : 3)} Z10 F{travel_speed * 60}
G0 E{if filament_multitool_ramming[initial_tool]}10{else}30{endif} X{(initial_tool == 0 ? 40 : (initial_tool == 1 ? 80 : (initial_tool == 2 ? 120 : (initial_tool == 3 ? 160 : 200))))} Z0.2 F{if filament_multitool_ramming[initial_tool]}500{else}170{endif}
G0 X{(initial_tool == 0 ? 40 : (initial_tool == 1 ? 80 : (initial_tool == 2 ? 120 : (initial_tool == 3 ? 160 : 200))))} E9 F800
G0 X{(initial_tool == 0 ? 43 : (initial_tool == 1 ? 83 : (initial_tool == 2 ? 123 : (initial_tool == 3 ? 163 : 203))))} Z0.05 F8000
G0 X{(initial_tool == 0 ? 46 : (initial_tool == 1 ? 86 : (initial_tool == 2 ? 126 : (initial_tool == 3 ? 166 : 206))))} Z0.2 F8000
G1 E{-1.5 * retract_length[initial_tool]} F2400
{e_retracted[initial_tool] = 1.5 * retract_length[initial_tool]}
G92 E0
